import React, { useEffect } from 'react';
import { Text, View } from 'react-native';
import BiometricAuth from 'react-native-biometrics';
import AsyncStorage from '@react-native-community/async-storage';

const BIOMETRIC_AUTH = "BIOMETRIC_AUTH";

function AuthenticationScreen() {
  useEffect(() => {
    checkBiometricAuth();
  }, []);

  const checkBiometricAuth = async () => {
    const biometricData = await BiometricAuth.isSensorAvailable();
    
    if (biometricData.available) {
      BiometricAuth.simplePrompt({
        promptMessage: 'Touch your fingerprint on the scanner to login', 
      }).then(() => {
        AsyncStorage.setItem(BIOMETRIC_AUTH, "1");
      });
    } else {
      // Fallback to password authentication
      console.log("Fallback to password authentication");
    }
  };
  
  return (
    <View>
      <Text>Authenticating...</Text>
    </View>
  );
}

export default AuthenticationScreen;